## Common patterns

### Filtering data by selection

A common use case is filtering lists or tables by a selected option:

```jsx live-dev
const App = () => {
  const [selectedCategory, setSelectedCategory] = useState<Key | null>(null);

  // Filter data based on selectedCategory
  const appliedFilter = selectedCategory
    ? `Showing items in category: ${selectedCategory}`
    : 'No filter applied';

  return (
    <Stack direction="column" gap="400">
      <Select.Root
        selectedKey={selectedCategory}
        onSelectionChange={setSelectedCategory}
        aria-label="Filter by category"
      >
        <Select.Options placeholder="All categories">
          <Select.Option id="electronics">Electronics</Select.Option>
          <Select.Option id="clothing">Clothing</Select.Option>
          <Select.Option id="books">Books</Select.Option>
        </Select.Options>
      </Select.Root>
      <Text fontSize="sm">{appliedFilter}</Text>
    </Stack>
  );
}
```

### Country/region selection

Example for selecting a country, region, or category:

```jsx live-dev
const App = () => {
  const [country, setCountry] = useState<Key | null>(null);

  return (
    <Stack direction="column" gap="400">
      <Select.Root
        selectedKey={country}
        onSelectionChange={setCountry}
        aria-label="Select country"
        isRequired
      >
        <Select.Options placeholder="Choose a country">
          <Select.Option id="us">United States</Select.Option>
          <Select.Option id="uk">United Kingdom</Select.Option>
          <Select.Option id="ca">Canada</Select.Option>
          <Select.Option id="de">Germany</Select.Option>
        </Select.Options>
      </Select.Root>
      {country && (
        <Text fontSize="sm">
          Selected country: {country}
        </Text>
      )}
    </Stack>
  );
}
```

## Testing your implementation

These examples demonstrate how to test your implementation when using Select within your application. As the component's internal functionality is already tested by Nimbus, these patterns help you verify your integration and application-specific logic.

### Basic Rendering Tests

Verify the component renders with expected elements

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen, waitFor } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { useState } from "react";
import type { Key } from "react-aria-components";
import { Select, NimbusProvider } from "@commercetools/nimbus";

describe("Select - Basic rendering", () => {
  it("renders select trigger button", () => {
    render(
      <NimbusProvider>
        <Select.Root aria-label="Select an option">
          <Select.Options>
            <Select.Option id="1">Option 1</Select.Option>
          </Select.Options>
        </Select.Root>
      </NimbusProvider>
    );

    expect(
      screen.getByRole("button", { name: /Select an option/ })
    ).toBeInTheDocument();
  });

  it("displays default placeholder text", () => {
    render(
      <NimbusProvider>
        <Select.Root aria-label="Select an option">
          <Select.Options>
            <Select.Option id="1">Option 1</Select.Option>
          </Select.Options>
        </Select.Root>
      </NimbusProvider>
    );

    // Default placeholder is "Select an item"
    expect(screen.getByText("Select an item")).toBeInTheDocument();
  });
});
```

### Interaction Tests

Test user interactions with the component

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen, waitFor } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { useState } from "react";
import type { Key } from "react-aria-components";
import { Select, NimbusProvider } from "@commercetools/nimbus";

describe("Select - Interactions", () => {
  it("opens dropdown when button is clicked", async () => {
    const user = userEvent.setup();
    render(
      <NimbusProvider>
        <Select.Root aria-label="Select an option">
          <Select.Options>
            <Select.Option id="1">Option 1</Select.Option>
            <Select.Option id="2">Option 2</Select.Option>
          </Select.Options>
        </Select.Root>
      </NimbusProvider>
    );

    const select = screen.getByRole("button", { name: /Select an option/ });
    await user.click(select);

    // The popover is rendered via a react portal outside of the select root
    // and can only be found by querying the document directly
    await waitFor(() => {
      const listbox = document.querySelector('[role="listbox"]');
      expect(listbox).toBeInTheDocument();
    });
  });

  it("selects an option when clicked", async () => {
    const user = userEvent.setup();
    const handleSelectionChange = vi.fn();
    render(
      <NimbusProvider>
        <Select.Root
          aria-label="Select an option"
          onSelectionChange={handleSelectionChange}
        >
          <Select.Options>
            <Select.Option id="1">Option 1</Select.Option>
            <Select.Option id="2">Option 2</Select.Option>
          </Select.Options>
        </Select.Root>
      </NimbusProvider>
    );

    const select = screen.getByRole("button", { name: /Select an option/ });
    await user.click(select);

    // Options are in the portal, query the document directly
    await waitFor(() => {
      const options = document.querySelectorAll('[role="option"]');
      expect(options.length).toBeGreaterThan(0);
    });
    const options = document.querySelectorAll('[role="option"]');
    await user.click(options[1]);

    expect(handleSelectionChange).toHaveBeenCalledWith("2");
  });
});
```

